hooks.onDraw:
const s = world.state;
const A = function (v) { return Math.max(0, Math.min(1, v || 0)); };
const PJS = ' "Plus Jakarta Sans", ui-sans-serif, system-ui';
const TAU = Math.PI * 2;
const T = world.t || 0;
const logo = world.props.find(function (p) { return p.id === 'logo'; });
// --- pajaritos en el cielo (aparecen con el parque) ---
if (s.park > 0.04) {
  ctx.save(); ctx.globalAlpha = A(s.park) * 0.85; ctx.strokeStyle = '#46506a'; ctx.lineWidth = 2; ctx.lineCap = 'round';
  for (let k = 0; k < 5; k++) {
    const dir = k % 2 ? 1 : -1;
    const bx = ((k * 230 + T * (18 + k * 4) * dir) % 1060 + 1060) % 1060 - 50;
    const by = 70 + k * 20 + Math.sin(T * 1.3 + k) * 6;
    const w = 8 + (k % 3), fl = 0.7 + 0.5 * Math.sin(T * 5 + k);
    ctx.beginPath(); ctx.moveTo(bx - w, by); ctx.quadraticCurveTo(bx - w * 0.4, by - w * fl, bx, by); ctx.quadraticCurveTo(bx + w * 0.4, by - w * fl, bx + w, by); ctx.stroke();
  }
  ctx.restore();
}
// --- elementos sobre las mesas (la noche del agobio) ---
if (s.mesas > 0.01) {
  ctx.save(); ctx.globalAlpha = A(s.mesas);
  // mesa 1: pila de libros
  (function () { const x = 175, y = 414; const cols = ['#7a5a4a', '#5a6a7a', '#6a5a7a']; for (let i = 0; i < 3; i++) { ctx.fillStyle = cols[i]; world.draw.rrect(x - 26 + i * 2, y - 6 - i * 9, 52 - i * 3, 9, 2); ctx.fill(); } })();
  // mesa 2: papeles + mapa enrollado
  (function () { const x = 470, y = 420; ctx.fillStyle = '#cfc8b6'; for (let i = 0; i < 3; i++) { world.draw.rrect(x - 30 + i * 6, y - 4 - i * 3, 44, 30, 2); ctx.fill(); } ctx.fillStyle = '#9a8f76'; world.draw.rrect(x + 20, y - 18, 12, 40, 6); ctx.fill(); })();
  // mesa 3: instrumentos (matraces)
  (function () { const x = 770, y = 416; const fc = ['#5b8d8a', '#8d5b6a']; for (let i = 0; i < 2; i++) { const fx = x - 14 + i * 28; ctx.fillStyle = '#cdd6d8'; ctx.beginPath(); ctx.moveTo(fx - 3, y - 18); ctx.lineTo(fx + 3, y - 18); ctx.lineTo(fx + 9, y); ctx.lineTo(fx - 9, y); ctx.closePath(); ctx.fill(); ctx.fillStyle = fc[i]; ctx.beginPath(); ctx.moveTo(fx - 6, y - 6); ctx.lineTo(fx + 6, y - 6); ctx.lineTo(fx + 9, y); ctx.lineTo(fx - 9, y); ctx.closePath(); ctx.fill(); } })();
  ctx.restore();
}
// --- borrador gris (mockup de genially) ---
if (s.draft > 0.01) {
  ctx.save(); ctx.globalAlpha = A(s.draft);
  const bx = 575, by = 318, bw = 210, bh = 138, L = bx - bw / 2, Tp = by - bh / 2;
  world.draw.rrect(L, Tp, bw, bh, 10); ctx.fillStyle = '#3a3f4e'; ctx.fill();
  world.draw.rrect(L, Tp, bw, bh, 10); ctx.lineWidth = 1.4; ctx.strokeStyle = '#565c70'; ctx.stroke();
  world.draw.rrect(L, Tp, bw, 18, 10); ctx.fillStyle = '#474d60'; ctx.fill();
  ctx.fillStyle = '#5a6076'; for (let r = 0; r < 3; r++) ctx.fillRect(L + 14, Tp + 32 + r * 15, 86, 6);
  ctx.fillStyle = '#525870'; ctx.fillRect(L + 116, Tp + 30, 78, 52);
  const sg = A(s.signed), rr = Math.round(92 + (244 - 92) * sg), g2 = Math.round(98 + (172 - 98) * sg), bb = Math.round(112 + (29 - 112) * sg);
  world.draw.rrect(L + 14, Tp + 84, 98, 38, 6); ctx.fillStyle = 'rgb(' + rr + ',' + g2 + ',' + bb + ')'; ctx.fill();
  ctx.restore();
}
// --- ruleta de verbos (AI Builder) ---
if (s.wheel > 0.01) {
  const wx = 575, wy = 318, wr = 64;
  ctx.save(); ctx.globalAlpha = A(s.wheel); ctx.translate(wx, wy);
  const verbs = ['λύω', 'γράφω', 'φέρω', 'λέγω', 'ἔχω', 'μένω'];
  const cols = ['#4f9dff', '#f4ac1d', '#e0607a', '#3ddc97', '#9b6cff', '#ff9d5c'];
  ctx.save(); ctx.rotate(T * 0.5);
  for (let i = 0; i < 6; i++) { const a0 = i / 6 * TAU, a1 = (i + 1) / 6 * TAU; ctx.beginPath(); ctx.moveTo(0, 0); ctx.arc(0, 0, wr, a0, a1); ctx.closePath(); ctx.fillStyle = cols[i]; ctx.fill(); const am = (a0 + a1) / 2; ctx.save(); ctx.rotate(am); ctx.fillStyle = '#10131f'; ctx.font = '700 13px' + PJS; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText(verbs[i], wr * 0.6, 0); ctx.restore(); }
  ctx.restore();
  ctx.fillStyle = '#10131f'; ctx.beginPath(); ctx.arc(0, 0, wr * 0.26, 0, TAU); ctx.fill();
  ctx.fillStyle = '#FBFAF6'; ctx.beginPath(); ctx.arc(0, 0, wr * 0.15, 0, TAU); ctx.fill();
  ctx.fillStyle = '#F4AC1D'; ctx.beginPath(); ctx.moveTo(0, -wr - 6); ctx.lineTo(-7, -wr + 7); ctx.lineTo(7, -wr + 7); ctx.closePath(); ctx.fill();
  ctx.restore();
}
// --- learners: docente + alumnos (con salto y brillo) ---
const ls = world.entities.filter(function (e) { return e.type === 'learner'; });
ls.sort(function (a, b) { return (a.y || 0) - (b.y || 0); });
for (let i = 0; i < ls.length; i++) {
  const e = ls[i];
  const isAl = e.id && e.id.charAt(0) === 'a' && e.id.charAt(1) === 'l';
  if (isAl && A(s.glow) > 0.02 && (e._alpha == null || e._alpha > 0.05)) {
    const gr = ctx.createRadialGradient(e.x, e.y + 6, 4, e.x, e.y + 6, 34);
    gr.addColorStop(0, 'rgba(255,236,170,' + (0.34 * A(s.glow)) + ')'); gr.addColorStop(1, 'rgba(255,236,170,0)');
    ctx.save(); ctx.fillStyle = gr; ctx.beginPath(); ctx.arc(e.x, e.y + 6, 34, 0, TAU); ctx.fill(); ctx.restore();
  }
  if (isAl && A(s.park) > 0.5) {
    const jump = Math.abs(Math.sin(T * 3.2 + i * 0.9)) * 7 * A(s.park);
    const oy = e.y; e.y = oy - jump; world.draw.learner(e); e.y = oy;
  } else {
    world.draw.learner(e);
  }
}
// --- noche: viñeta que se levanta hacia el amanecer ---
if (s.night > 0.01) {
  const g = ctx.createRadialGradient(470, 360, 90, 470, 360, 660);
  g.addColorStop(0, 'rgba(8,11,22,' + (0.10 * s.night) + ')');
  g.addColorStop(1, 'rgba(8,11,22,' + (0.86 * s.night) + ')');
  ctx.save(); ctx.fillStyle = g; ctx.fillRect(0, 0, world.W, world.H); ctx.restore();
}
// --- telar de luz de Genially (sobre la noche) ---
if (s.loom > 0.01 && logo) {
  const ix = logo.x, iy = logo.y + 18, bx = 575, by = 300;
  ctx.save(); ctx.globalAlpha = A(s.loom);
  for (let k = 0; k < 7; k++) { const p = k / 6, tx = bx - 86 + p * 172, ty = by; const a = 0.22 + 0.34 * (0.5 + 0.5 * Math.sin(T * 3 + k)); ctx.strokeStyle = 'rgba(120,210,255,' + a + ')'; ctx.lineWidth = 1.3; ctx.beginPath(); ctx.moveTo(ix, iy); ctx.quadraticCurveTo((ix + tx) / 2, (iy + ty) / 2 - 18, tx, ty); ctx.stroke(); }
  ctx.restore();
}
// --- resplandor de Genially (perfora la noche al subir) ---
if (logo && (logo.alpha || 0) > 0.02) {
  const gg = ctx.createRadialGradient(logo.x, logo.y, 6, logo.x, logo.y, 70);
  gg.addColorStop(0, 'rgba(180,200,255,' + (0.30 * logo.alpha) + ')'); gg.addColorStop(1, 'rgba(180,200,255,0)');
  ctx.save(); ctx.fillStyle = gg; ctx.beginPath(); ctx.arc(logo.x, logo.y, 70, 0, TAU); ctx.fill(); ctx.restore();
}
// --- baño cálido del parque ---
if (s.warm > 0.01) { ctx.save(); ctx.globalAlpha = s.warm * 0.12; ctx.fillStyle = '#f4c87a'; ctx.fillRect(0, 0, world.W, world.H); ctx.restore(); }
